from pathlib import Path


def looks_generated(path: Path, text: str) -> bool:
    """Dosya adi ve baslik isaretlerinden uretilmis dosyayi sezgisel bulur."""
    filename = path.name.lower()
    generated_name_markers = (
        ".min.",
        "bundle",
        "generated",
        "autogen",
        ".g.",
        "pb2",
        "swagger",
        "openapi",
    )
    if any(marker in filename for marker in generated_name_markers):
        return True

    header = "\n".join(text.splitlines()[:5]).lower()
    generated_header_markers = (
        "auto-generated",
        "autogenerated",
        "generated by",
        "do not edit",
        "code generated",
    )
    return any(marker in header for marker in generated_header_markers)


def looks_minified(text: str) -> bool:
    """Satir uzunlugu ve yogunluguyla minify kodu sezgisel tespit eder."""
    lines = text.splitlines()
    if not lines:
        return True

    avg_line_len = sum(len(line) for line in lines) / max(len(lines), 1)
    very_long_lines = sum(1 for line in lines if len(line) > 220)
    compact_ratio = sum(1 for line in lines if line.strip()) / max(len(lines), 1)

    return avg_line_len > 180 and very_long_lines >= 2 and compact_ratio > 0.95


def is_valid_source(path: Path, text: str, min_file_lines: int) -> bool:
    """Dosya bos degilse, yeterince uzunsa ve bilgi tasiyorsa True doner."""
    lines = text.splitlines()
    if len(lines) < min_file_lines:
        return False
    if looks_generated(path, text):
        return False
    if looks_minified(text):
        return False
    if not text.strip():
        return False
    return True
